<template>
    <section class="page-action">
        <div class="row">
            <div class="col-md-12 padding-t_8">
                <div class="theme-primary partition-full">
                    <span class="p-name text-white">{{ $t('ProjectRequest') }}</span>
                    <span class="p-actions float-right">
                        <a href="javascript:;" class="p-action-btn text-white float-right" @click="Close"><i
                                class="fa fa-angle-double-left pr-2"></i><br>{{ $t('BacktoList') }}</a>
                    </span>
                </div>
            </div>
        </div>
        <div class="row">
            <div class="col-md-12 padding-t_8">
                <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm"
                    :mandatorytext="MandatoryString" v-on:OnSubmit="onSubmit">
                </dynamic-form>
                <div class="clearfix"></div>
                <div class="listing tab-content mt-2" id="divconversationbox" v-if="CommentData.length > 0">
                    <div class="col-12 d-flex border border-bottom-0 bg-f5f5f5">
                        <div class="col-md-6 pl-0">
                            <h6 class="py-3 mb-0">
                                {{ $t('Comments') }}
                            </h6>
                        </div>
                        <div class="col-md-6 text-right pr-0 bottom_filter_button">
                            <a @click="togglePanels" id="ancreplyExpandAllCollapseAll" class="position-relative"
                                style="z-index:999;" :title="$t('  ')" data-toggle-tooltip="tooltip">{{
                                    $t('ExpandAllCollapseAll') }}</a>
                        </div>
                    </div>
                    <div class="card" v-for="(item, parentIndex) in CommentData" :index="parentIndex">
                        <div class="card-header">
                            <a class="card-link collapsed" :href="'#Expensecollapse' + parentIndex"
                                @click.prevent="togglePanel(parentIndex)">
                                <div class="conversation-date heading-border">
                                    <span><em class="pr-1" aria-hidden="true"></em>{{ item.groupKey }}</span>
                                </div>
                            </a>
                        </div>
                        <div v-bind:id="'Expensecollapse' + parentIndex"
                            v-bind:class="{ 'collapse': true, 'show': parentIndex == 0 }"
                            :class="{ 'collapse': true, 'show': item.isOpen }">
                            <div class="card-body" v-for="(childItem, childIndex) in item.groupData" :key="childIndex">
                                <div class="conversation-main">
                                    <div class="conversation-time">
                                        <span>{{ formatTime(childItem.CREATEDAT) }}</span>
                                    </div>
                                    <div class="conversation-box-con">
                                        <div class="conversation-box">
                                            <div class="name-circle light-yellow">
                                                <!-- <img class="img-circle avatar" :src="blobUrl" width="51" height="51"
                                                    alt="Image" /> -->
                                                <span class="mt-2"> {{ getInitials(childItem.POSTEDBYNAME) }}</span>
                                            </div>

                                            <div class="conversation-header addednote-ticket">
                                                <span>
                                                    <span class="sender-name">{{ childItem.NOTES }}</span>
                                                </span>
                                            </div>
                                            <div class="conversation-content">
                                                <div class="col-12 p-0 notesdata">
                                                    <h6 class="text-muted time">
                                                        <i>
                                                            <b>{{ childItem.POSTEDBYNAME }}</b>, {{ $t('PostedOn') }}:
                                                            <span class="text-danger">
                                                                {{ TimeAgo(childItem.CREATEDAT) }}
                                                            </span>
                                                        </i>
                                                    </h6>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
                <div class="listing">
                    <div class="heading-border mt-3 mb-2">
                        <h5 class="h5">
                            <span>{{ $t('Attachment') }}</span>
                        </h5>
                    </div>
                    <div class="table-responsive table-fix-header">
                        <table class="table-sorting table table-bordered mb-0">
                            <thead class="thead-bg">
                                <tr>
                                    <th class="text-center"><span class="text-center">#</span></th>
                                    <th class="text-center"><span>{{ $t('AttachmentName') }}</span></th>
                                    <th class="text-center"><span>{{ $t('Action') }}</span></th>
                                </tr>
                            </thead>
                            <tbody>
                                <tr v-if="ViewFilesData.length == 0">
                                    <td class="text-center text-danger no-record" colspan="3">
                                        <span>{{ $t('NoRecordfound') }}</span>
                                    </td>
                                </tr>

                                <tr v-for="(item, index) in ViewFilesData" :key="index"
                                    :class="index + 1 % 2 === 0 ? 'row' : 'gray'">
                                    <td class="text-center">
                                        {{ index + 1 }}
                                    </td>
                                    <td class="text-center">
                                        {{ item.ATTACHMENTNAME }}
                                    </td>
                                    <td class="text-center single-action">
                                        <a href="javascript:;" @click="downloadfile(item.PROJECTREQUESTATTACHMENTID)"
                                            class="downloadfile text-success" :title="$t('DownloadFile')"
                                            :value="item.PROJECTREQUESTATTACHMENTID" :filePath="item.ATTACHMENTPATH"
                                            :fileType="item.ATTACHMENTTYPE">
                                            <em class="fa fa-download"></em>
                                        </a>
                                        <a class="dd-btn deletefile  text-danger ml-2"
                                            @click="DeleteFile(item.PROJECTREQUESTATTACHMENTID)"
                                            :value="item.PROJECTREQUESTATTACHMENTID" :title="$t('Delete')"
                                            :filePath="item.ATTACHMENTPATH" :fileType="item.ATTACHMENTTYPE">
                                            <em class="fa fa-trash-o"></em>
                                        </a>
                                    </td>
                                </tr>
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        </div>
    </section>

</template>
<script>
import moment from 'moment';
import DataService from '../../../services/DataService'
export default {
    data() {
        return {
            CommentData: [],
            PostComment: 'Y',
            blobUrl: '',
            StatusCode: '',
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            QuotationId: null,
            UserType: null,
            ViewFilesData: [],
            FormSchema: [
                {
                    layoutType: "four",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Title'),
                            name: "Title",
                            value: "",
                            placeholder: this.$t('Enter Title'),
                            validationRules: { "required": false, max: 100 },
                            disabled: true,
                        },
                        {
                            astype: "TextField",
                            label: this.$t('Budget'),
                            name: "Budget",
                            value: "",
                            placeholder: this.$t('Enter Budget'),
                            validationRules: { "required": false, max: 100 },
                            disabled: true,
                        },
                        {
                            astype: "TextField",
                            label: this.$t('Start Date'),
                            name: "StartDate",
                            value: "",
                            placeholder: this.$t('Enter Start Date'),
                            validationRules: { "required": false, max: 100 },
                            disabled: true,
                        },
                        {
                            astype: "TextField",
                            label: this.$t('Due Date'),
                            name: "DueDate",
                            value: "",
                            placeholder: this.$t('Enter Due Date'),
                            validationRules: { "required": false, max: 100 },
                            disabled: true,
                        },

                    ]
                },
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",
                            placeholder: this.$t('Enter Description'),
                            validationRules: { "required": false, max: 100 },
                            disabled: true,
                        }
                    ]
                },
                {
                    layoutType: "single",
                    group_name: 'Post New Comment',
                    Data: [
                        {
                            astype: "TextAreaField",
                            label: this.$t('Description'),
                            name: "tDescription",
                            value: "",
                            placeholder: this.$t('Enter Description'),
                            validationRules: { "required": true, max: 100 },
                            config: {
                                rows: 2
                            }
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-info",
                    text: "<i class='fa fa-send pr-2'></i>Post New Comment",
                    isVisible: true
                }
            ],
            CurrencyCode: '',
            smsSendingTime: '',
        }
    },
    created: function () {
        var ths = this;
        ths.QuotationId = ths.$route.params.QuotationId;
        ths.UserType = ths.GetUserInfo.UserType;
        ths.CurrencyCode = ths.GetUserInfo.Currency.replace(/[()]/g, '');
        ths.GetDetails();
        ths.AddProjectRequestNotes();
        ths.ViewFiles();
    },
    methods: {
        DeleteFile: function (id) {
            var vm = this;
            var val = "";
            vm.isLoading = true;
            if (id == null) {

                $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                    if (val.length > 0)
                        val += ',';
                    val += $(this).val();
                });
            }
            else {
                val = id;
            }
            if (val != null) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("File")), function () {
                    var postJSON = {
                        ids: val,
                        MODULENAME: "PROJECT",
                        refCode: "PROJECT_REQUEST_File"
                    };
                    var objectPostString = JSON.stringify(postJSON);
                    DataService.CommonCommonDelete(objectPostString).then(function (response) {
                        vm.isLoading = false;
                        if (response.status == 200) {
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('File')]), "success", true, vm.$t("Alert"));
                            vm.GetDetails();
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('File')]), "Success", true, vm.$t("Alert"));
                        }
                    });
                });
            }
            else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }
            vm.isLoading = false;
        },
        removeHtmlTags(content) {
            return content.replace(/<[^>]+>/g, '');
        },
        togglePanels() {
            const anyOpen = this.CommentData.some(item => item.isOpen);
            this.CommentData.forEach(item => { item.isOpen = !anyOpen; });
        },
        togglePanel(index) {
            this.CommentData[index].isOpen = !this.CommentData[index].isOpen;
        },
        TimeAgo: function (value) {
            if (value) {
                debugger
                const timestamp = moment.utc(value).utcOffset("+05:30");
                const now = moment.utc().utcOffset("+05:30");
                const yearsAgo = now.diff(timestamp, 'years');
                const monthsAgo = now.diff(timestamp, 'months');
                const daysAgo = now.diff(timestamp, 'days');
                const hoursAgo = now.diff(timestamp, 'hours');
                const minutesAgo = now.diff(timestamp, 'minutes');
                const secondsAgo = now.diff(timestamp, 'seconds');

                if (yearsAgo > 0) {
                    return `${yearsAgo} year(s) ago`;
                } else if (monthsAgo > 0) {
                    return `${monthsAgo} month(s) ago`;
                } else if (daysAgo > 0) {
                    return `${daysAgo} day(s) ago`;
                } else if (hoursAgo > 0) {
                    return `${hoursAgo} hour(s) ago`;
                } else if (minutesAgo > 0) {
                    return `${minutesAgo} minute(s) ago`;
                } else {
                    return `${secondsAgo} second(s) ago`;
                }
            }
        },
        formatTime(value) {
            if (!value) return "";
            const timestamp = moment.utc(value).utcOffset("+05:30");
            const now = moment.utc().utcOffset("+05:30");
            return timestamp.format("hh:mm A");
        },
        AddProjectRequestNotes: function () {
            var ths = this;
            var url = `Prid=${ths.QuotationId}`;
            DataService.AddProjectRequestNotes(url).then(function (response) {
                if (response.data.result.length > 0) {
                    var fullJSON = response.data.result;
                    ths.CommentData = [];
                    var gruopBy = "";
                    $.each(fullJSON, $.proxy(function (index, item) {
                        gruopBy = ths.$options.filters.formatDate(item.CREATEDAT);
                        var chkGroup = $.grep(ths.CommentData, function (element, index) {
                            return element.groupKey == gruopBy;
                        }
                        );
                        if (chkGroup.length == 0) {
                            var returnedData = $.grep(fullJSON, function (element, index) {
                                return ths.$options.filters.formatDate(element.CREATEDAT) == gruopBy;
                            }
                            );
                            if (returnedData.length > 0) {
                                var objGroup = {
                                    groupKey: gruopBy,
                                    isOpen: false,
                                    groupData: returnedData,
                                };
                                ths.CommentData.push(objGroup);
                                ths.avatar = ths.CommentData[0].groupData[0].avatar;
                            }
                        }
                    }, this));
                } else {
                    ths.CommentData = [];
                }
            })
        },
        GetDetails: function () {
            var ths = this;
            var url = `id=${ths.QuotationId}`;
            DataService.GetDetails(url).then((response) => {
                if (response.data.result.data.length > 0) {
                    ths.FormSchema[0].Data[0].value = response.data.result.data[0].PROJECTTITLE;
                    ths.FormSchema[0].Data[2].value = response.data.result.data[0].STARTDATE;
                    ths.FormSchema[0].Data[3].value = response.data.result.data[0].DUEDATE;
                    ths.FormSchema[0].Data[1].value = response.data.result.data[0].BUDGET.toFixed(2);
                    ths.FormSchema[1].Data[0].value = ths.removeHtmlTags(response.data.result.data[0].DESCRIPTION);
                    ths.StatusCode = response.data.result.data[0].STATUSCODE;
                    if (ths.StatusCode == 'PRO_REQ_CONVERTED' || ths.StatusCode == 'PRO_REQ_REJECTED') {
                        ths.PostComment = 'N';
                    }
                }
            })
        },
        ViewFiles: function () {
            var ths = this;
            var url = `id=${ths.QuotationId}`;
            DataService.ViewFiles(url).then((response) => {
                if (response.data.result.length > 0) {
                    ths.ViewFilesData = response.data.result;
                }
            })
        },
        downloadfile: function (name) {
            var vm = this;
            vm.isLoading = true;
            var val = name;
            var params = `fileId=${vm.QuotationId}`;
            DataService.DownloadSingleFile(params).then((response) => {
                if (response.data != null) {
                    var fileURL = window.URL.createObjectURL(new Blob([response.data]));
                    var fileLink = document.createElement('a');
                    fileLink.href = fileURL;
                    fileLink.setAttribute('download', name);
                    document.body.appendChild(fileLink);
                    fileLink.click();
                    vm.isLoading = false;
                }
                else {
                    vm.isLoading = false;
                    vm.ShowAlert(vm.$t("FileNotDownload"), "warning", true, vm.$t("Alert"));
                }

            })
        },
        onSubmit() {
            var vm = this;
            var commentMessage = vm.$refs.AssignTagForm.getPropertyValue("tDescription", "value");
            var obj = {
                Prid: Number(vm.QuotationId),
                notes: commentMessage,
                prtitle: vm.FormSchema[0].Data[0].value,
                createdbyname: vm.GetUserInfo.Name,
                createdby: vm.GetUserInfo.ID,
                type: 'PRO_REQ_COMMENT'
            }
            var url = JSON.stringify(obj);
            DataService.SaveProjectRequestNotes(url).then((response) => {
                if (response.data != null) {
                    if (response.data.response == 'success') {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Comment')]), "success", true, vm.$t("Alert"));
                        vm.$refs.AssignTagForm.updateProperty("tDescription", "value", '');
                        vm.AddProjectRequestNotes();
                        vm.GetDetails();
                    }
                    else {
                        vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                    }
                }

            });
        },
        getInitials(fullName) {
            if (!fullName) return '';
            const parts = fullName.trim().split(' ');
            let initials = '';

            for (let i = 0; i < parts.length; i++) {
                if (parts[i].length > 0) {
                    initials += parts[i][0].toUpperCase();
                }
            }
            return initials;
        },
        Close() {
            this.$router.push({ name: 'ProjectRequestList' });
        }
    }
}
</script>